        optsChartData.labels[0].forEach((label, idx) => {
          strXml += `<c:pt idx="${idx}"><c:v>${encodeXmlEntities(label)}</c:v></c:pt>`;
        });
        strXml += "    </c:strCache>";
        strXml += "  </c:strRef>";
        strXml += "</c:cat>";
        strXml += "  <c:val>";
